var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>파견된 직원들이 전원 연락 두절 상태입니다!</color>","JPN":"<color=#ffd34c>派遣された社員全員から連絡が途絶えています！</color>","ENG":"<color=#ffd34c>We lost comms to all the operatives!</color>","TWN":"<color=#ffd34c>派出去的員工目前都失聯中！</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>신호가 끊긴 그릴 파티 녀석들을 발견했다! 전부 기절해 있어!</color>","JPN":"<color=#ffd34c>信号が途切れたグリルパーティーのやつらを発見したぞ！　全員気絶している！</color>","ENG":"<color=#ffd34c>I've got eyes on Grill Party that went radio silent! They're all unconscious!</color>","TWN":"<color=#ffd34c>發現信號中斷的格里爾派提的傢伙們！全數昏厥中。</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"시, 시청자 여러분! 저희는 지금 샤레이드에 나와 있는데요……!","JPN":"し、視聴者の皆さん！　私たちは今シャレードに来ています……！","ENG":"H-hello everyone… We're in Charade right now!","TWN":"觀…觀眾朋友！我們現在的位置是查雷德……！"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저기 하늘에 함선들 보이세요? 샤레이드에 있는 태스크포스들은 전부 출동한 거 같아요!","JPN":"空にいる艦船の数がわかりますか？　シャレードにいるすべてのタスクフォースカンパニーが出動したようです！","ENG":"See those ships in the sky? It seems like every TASKFORCE in Charade is on the move!","TWN":"有看到在天上的艦船嗎？查雷德的特遣勢力似乎全員出動中喔！"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"다들 그 얘기 들었지? 그 사채업자만 잡으면 관리국이 현상금을 두둑하게 준다던데?","JPN":"みんな、あの話を聞いたわよね？　あの闇金業者を捕まえたら管理局から懸賞金をたっぷりもらえるって！","ENG":"You guys heard the news, right? The Administration is offering one heck of a bounty for whoever catches that loan shark!","TWN":"大家應該都有聽說吧？只要逮到那個放高利貸的，管理局好像就大大有賞喔？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"이거 혹시 나를 위해 마련된 찬스?","JPN":"これはもしかして、アタシのために用意されたチャンスかしら？","ENG":"Could this be the chance of my life?","TWN":"難道這是上天給我的大好機會？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"여기서 활약하면 단숨에 유명인이 될 수 있다구!","JPN":"ここで活躍すれば一気に有名人になれるっ！","ENG":"If I kick some serious butt with this, I might become a superstar!","TWN":"只要這時候表現突出，應該就可以立刻爆紅吧！"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아, 안 돼! 루미야! 저런 난장판에 끼어들면 큰일나!","JPN":"だ、だめだよ、ルミちゃん！　あんな乱闘の場に乗り込んだら大変なことになるよ！","ENG":"No! Lumi! You don't want to get mixed up in that mess, trust me!","TWN":"不…不可以啦，魯米！不要去淌那個渾水！"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"관리국 직할 도시이기 때문인지 방해가 계속되는군요.","JPN":"管理局直轄都市だからか、妨害が絶えませんね。","ENG":"So the interference continues, perhaps due to this city's ADC status.","TWN":"因為是管理局的直轄市嗎？一直會有阻礙出現。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 윌버, 이걸 믿고 지불을 거절한다면 신속히 생각을 바꿔야 할 겁니다.","JPN":"しかしウィルバー、この状況に頼って返済を拒絶し続けるなら、今のうちに考え直したほうがいいでしょう。","ENG":"But mark my words, Wilbur. You may want to rethink your strategy if you believe this will prevent me from collecting what is owed to me.","TWN":"不過韋爾伯，如果你以為這樣就可以不還錢，那你很快就會改變想法的。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"사격 감지. 탄착군 패턴 분석 결과 입체기동 중인 아라크네로 판명.","JPN":"射撃感知。射弾パターン分析の結果、立体起動中のアラクネと判明。","ENG":"Gunfire detected. Ballistic analysis suggests the source of fire is an Arachne in motion.","TWN":"感應到射擊，模式分析結果，判斷是立體機動中的阿拉克涅。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"도시관리국에서 파견되었습니다. 수배자는 즉시 무장을 해제하고 투항하십시오.","JPN":"都市管理局から派遣されました。指名手配被疑者は直ちに武装を解除して投降してください。","ENG":"This law enforcement activity is sanctioned by City Management. Put down your weapon and surrender immediately.","TWN":"受城市管理局之託而來，請通緝犯立刻放下武器投降。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"본 기체들은 퓨처 앳 워 재단에서 공여되었습니다.","JPN":"本機体はフューチャーアットウォー財団から供与されました。","ENG":"These machines have been supplied by the Future-at-War Foundation.","TWN":"本機體是由天啟兵器財團贈與。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……퓨처 앳 워 프로젝트가 남긴 찌꺼기로 연명하는 자들이 보낸 기체들이군요.","JPN":"……フューチャーアットウォープロジェクトの残滓で延命している者たちが送った機体ですね。","ENG":"…So you've been deployed by those who prolonged their lives with the leftovers from Future-at-War projects.","TWN":"……原來是天啟兵器計畫遺留下來的禍害派來的。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 아무리 펌웨어 업데이트를 해도 대인 기총으로 저를 저지할 수 있는 가능성은 0입니다.","JPN":"しかし、いくらファームウェアアップデートをしたところで対人機銃で私を阻止できる可能性は0です。","ENG":"But your anti-personnel rifles have exactly zero chance of neutralizing me, regardless of your firmware version.","TWN":"不過就算再怎麼更新韌體，可以用槍打死我的機率是0。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};